message.content:
This is a complete HTML document that creates an interactive aquarium animation. You can click to drop fish food, and the fish will realistically chase and eat it.
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>🐠 interactive aquarium · fish & food</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    body {
      background: #0b1a2f;
      min-height: 100vh;
      display: flex;
      justify-content: center;
      align-items: center;
      font-family: system-ui, 'Segoe UI', Roboto, sans-serif;
    }
    .aquarium-wrapper {
      background: #0f2a44;
      padding: 20px 20px 30px;
      border-radius: 40px 40px 20px 20px;
      box-shadow: 0 20px 30px rgba(0,0,0,0.7), inset 0 0 0 2px #7ab7d0;
    }
    canvas {
      display: block;
      width: 900px;
      height: 550px;
      border-radius: 24px;
      box-shadow: inset 0 0 40px #1c4b6e, 0 8px 18px black;
      cursor: crosshair;
      background: radial-gradient(circle at 20% 30%, #1f6a8a, #0b334a);
      transition: filter 0.2s;
    }
    .caption {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-top: 14px;
      color: #b3def5;
      font-weight: 500;
      padding: 0 10px;
    }
    .food-count {
      background: #1a405a;
      padding: 6px 16px;
      border-radius: 40px;
      font-size: 0.9rem;
      letter-spacing: 0.5px;
      box-shadow: inset 0 2px 5px #0d2538;
    }
    .caption span:last-child {
      font-size: 0.85rem;
      opacity: 0.8;
    }
  </style>
</head>
<body>
<div class="aquarium-wrapper">
  <canvas id="aquariumCanvas" width="900" height="550"></canvas>
  <div class="caption">
    <span class="food-count">🍕 food pieces: <span id="foodCounter">0</span></span>
    <span>🖱️ left click → drop food</span>
  </div>
</div>
<script>
  (function(){
    const canvas = document.getElementById('aquariumCanvas');
    const ctx = canvas.getContext('2d');
    const foodSpan = document.getElementById('foodCounter');

    // ----------  aquarium dimensions  ----------
    const W = 900, H = 550;

    // ----------  fish population  ----------
    const FISH_COUNT = 13;
    let fishes = [];

    // food array
    let foodPellets = [];

    // ----------  Fish factory  ----------
    function createFish(x, y) {
      // random vibrant colors (hue)
      const hue = Math.floor(Math.random() * 360);
      const sat = 70 + Math.floor(Math.random() * 30); // 70-100
      const light = 45 + Math.floor(Math.random() * 30); // 45-75
      const bodyColor = `hsl(${hue}, ${sat}%, ${light}%)`;
      const finColor = `hsl(${hue}, ${sat-10}%, ${light-12}%)`;

      // size: 0.7 .. 1.5 (base 22px)
      const sizeFactor = 0.75 + Math.random() * 0.85; // 0.75 .. 1.6
      const bodyLength = Math.round(22 * sizeFactor);
      const bodyHeight = Math.round(12 * sizeFactor);

      // swimming behaviour
      const speed = 0.4 + Math.random() * 0.55; // 0.4 .. 0.95
      const angle = Math.random() * 2 * Math.PI;

      return {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        speed: speed,
        angle: angle,
        bodyColor,
        finColor,
        bodyLength,
        bodyHeight,
        sizeFactor,
        // tail animation
        tailPhase: Math.random() * 100,
        // personality: slight randomness
        wobble: 0.002 + Math.random() * 0.005,
      };
    }

    // initialise fishes
    function initFishes() {
      fishes = [];
      for (let i = 0; i < FISH_COUNT; i++) {
        let x = 60 + Math.random() * (W - 120);
        let y = 40 + Math.random() * (H - 100);
        fishes.push(createFish(x, y));
      }
    }
    initFishes();

    // ----------  utilities  ----------
    function dist(x1, y1, x2, y2) {
      return Math.hypot(x2 - x1, y2 - y1);
    }

    // ----------  food interaction  ----------
    // left click: place food
    canvas.addEventListener('click', (e) => {
      const rect = canvas.getBoundingClientRect();
      const scaleX = canvas.width / rect.width;
      const scaleY = canvas.height / rect.height;
      const mouseX = (e.clientX - rect.left) * scaleX;
      const mouseY = (e.clientY - rect.top) * scaleY;

      // clamp inside aquarium (with margin)
      const x = Math.min(W - 15, Math.max(15, mouseX));
      const y = Math.min(H - 15, Math.max(15, mouseY));
      foodPellets.push({ x, y, size: 5 + Math.random() * 3 });
      updateFoodCounter();
    });

    function updateFoodCounter() {
      foodSpan.textContent = foodPellets.length;
    }

    // ----------  fish AI  ----------
    function updateFish(fish, idx) {
      // if food exists -> chase nearest food
      if (foodPellets.length > 0) {
        let nearest = null;
        let minDist = Infinity;
        for (let i = 0; i < foodPellets.length; i++) {
          const f = foodPellets[i];
          const d = dist(fish.x, fish.y, f.x, f.y);
          if (d < minDist) {
            minDist = d;
            nearest = f;
          }
        }
        if (nearest) {
          const dx = nearest.x - fish.x;
          const dy = nearest.y - fish.y;
          const angleToFood = Math.atan2(dy, dx);
          // smooth turning (proportional)
          let diff = angleToFood - fish.angle;
          // normalise to -PI .. PI
          while (diff > Math.PI) diff -= 2 * Math.PI;
          while (diff < -Math.PI) diff += 2 * Math.PI;
          fish.angle += diff * 0.09 + (Math.random() - 0.5) * 0.015; // slight wander

          // increase speed when hungry (but not too fast)
          const targetSpeed = Math.min(fish.speed * 1.7, 1.6);
          const currentSpeed = Math.hypot(fish.vx, fish.vy);
          const newSpeed = currentSpeed + (targetSpeed - currentSpeed) * 0.1;
          fish.vx = Math.cos(fish.angle) * newSpeed;
          fish.vy = Math.sin(fish.angle) * newSpeed;

          // if very close to food -> eat it!
          if (minDist < 12 + fish.bodyLength * 0.25) {
            const index = foodPellets.indexOf(nearest);
            if (index !== -1) {
              foodPellets.splice(index, 1);
              updateFoodCounter();
              // after eating, slow down a little
              const curSpd = Math.hypot(fish.vx, fish.vy);
              const slowDown = curSpd * 0.7;
              fish.vx = Math.cos(fish.angle) * slowDown;
              fish.vy = Math.sin(fish.angle) * slowDown;
            }
          }
        }
      } else {
        // no food: free swimming with gentle wandering
        // gradually return to base speed
        const baseSpeed = fish.speed;
        const currentSpeed = Math.hypot(fish.vx, fish.vy);
        const newSpeed = currentSpeed + (baseSpeed - currentSpeed) * 0.02;
        fish.vx = Math.cos(fish.angle) * newSpeed;
        fish.vy = Math.sin(fish.angle) * newSpeed;

        // random turn
        fish.angle += (Math.random() - 0.5) * 0.04;
      }

      // update position
      fish.x += fish.vx;
      fish.y += fish.vy;

      // boundary reflection with smooth turn
      const margin = 25;
      const bounceForce = 0.25;
      if (fish.x < margin) {
        fish.x = margin;
        fish.angle = Math.PI - fish.angle; 
        fish.vx = Math.abs(fish.vx) * 0.7;
      } else if (fish.x > W - margin) {
        fish.x = W - margin;
        fish.angle = Math.PI - fish.angle;
        fish.vx = -Math.abs(fish.vx) * 0.7;
      }
      if (fish.y < margin) {
        fish.y = margin;
        fish.angle = -fish.angle;
        fish.vy = Math.abs(fish.vy) * 0.7;
      } else if (fish.y > H - margin) {
        fish.y = H - margin;
        fish.angle = -fish.angle;
        fish.vy = -Math.abs(fish.vy) * 0.7;
      }

      // tail animation increment
      fish.tailPhase += 0.08 + Math.random() * 0.03;
    }

    // ----------  DRAWING  ----------
    function drawBackground() {
      // gradient water
      const grad = ctx.createRadialGradient(150, 150, 80, 400, 300, 700);
      grad.addColorStop(0, '#247a9e');
      grad.addColorStop(0.5, '#145d7a');
      grad.addColorStop(1, '#08304b');
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, W, H);

      // underwater light rays
      ctx.save();
      ctx.globalAlpha = 0.08;
      for (let i = 0; i < 6; i++) {
        ctx.beginPath();
        ctx.moveTo(80 + i*130, 0);
        ctx.lineTo(30 + i*140, H);
        ctx.lineTo(130 + i*140, H);
        ctx.closePath();
        ctx.fillStyle = '#d4f0ff';
        ctx.fill();
      }
      ctx.restore();

      // sandy bottom
      ctx.fillStyle = '#b8a28c';
      ctx.beginPath();
      ctx.rect(0, H-35, W, 40);
      ctx.fill();
      // pebbles
      ctx.fillStyle = '#6f5e4e';
      for (let i=0; i<14; i++) {
        ctx.beginPath();
        ctx.ellipse(40 + i*70, H-28, 18, 7, 0, 0, Math.PI*2);
        ctx.fillStyle = `hsl(30, 10%, ${25 + i*3}%)`;
        ctx.fill();
      }
      // plants
      ctx.shadowColor = '#0e3a2b';
      ctx.shadowBlur = 12;
      for (let i=0; i<9; i++) {
        let px = 50 + i*100;
        ctx.beginPath();
        ctx.moveTo(px, H-30);
        ctx.quadraticCurveTo(px-15, H-70, px+8, H-90);
        ctx.quadraticCurveTo(px+20, H-70, px+5, H-30);
        ctx.fillStyle = `hsl(130, 60%, ${25 + i*4}%)`;
        ctx.shadowColor = '#0f3f2b';
        ctx.fill();
      }
      ctx.shadowBlur = 0;
    }

    function drawFish(fish) {
      const { x, y, bodyLength, bodyHeight, bodyColor, finColor, tailPhase, angle, sizeFactor } = fish;
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);

      // body (ellipse)
      ctx.beginPath();
      ctx.ellipse(0, 0, bodyLength/2, bodyHeight/2, 0, 0, Math.PI * 2);
      ctx.fillStyle = bodyColor;
      ctx.shadowColor = 'rgba(0,0,0,0.3)';
      ctx.shadowBlur = 8;
      ctx.fill();
      ctx.shadowBlur = 0;

      // tail (animated)
      const tailWag = Math.sin(tailPhase) * 0.2 + 0.8;
      ctx.save();
      ctx.translate(-bodyLength/2 + 2, 0);
      ctx.beginPath();
      ctx.moveTo(0, -bodyHeight/2 * 0.8);
      ctx.lineTo(-bodyLength/3 * tailWag, 0);
      ctx.lineTo(0, bodyHeight/2 * 0.8);
      ctx.closePath();
      ctx.fillStyle = finColor;
      ctx.shadowBlur = 6;
      ctx.shadowColor = 'rgba(0,0,0,0.25)';
      ctx.fill();
      ctx.restore();

      // dorsal fin
      ctx.save();
      ctx.translate(4, -bodyHeight/2 + 2);
      ctx.beginPath();
      ctx.moveTo(0, 0);
      ctx.lineTo(6, -bodyHeight/2 * 0.8);
      ctx.lineTo(-4, -bodyHeight/2 * 0.4);
      ctx.closePath();
      ctx.fillStyle = finColor;
      ctx.shadowBlur = 4;
      ctx.fill();
      ctx.restore();

      // pectoral fin (small)
      ctx.save();
      ctx.translate(6, bodyHeight/2 - 3);
      ctx.beginPath();
      ctx.moveTo(0, 0);
      ctx.lineTo(8, bodyHeight/3);
      ctx.lineTo(2, bodyHeight/4);
      ctx.closePath();
      ctx.fillStyle = finColor;
      ctx.shadowBlur = 2;
      ctx.fill();
      ctx.restore();

      // eye
      ctx.shadowBlur = 0;
      ctx.beginPath();
      ctx.arc(bodyLength/4, -bodyHeight/5, bodyLength/8, 0, 2 * Math.PI);
      ctx.fillStyle = '#fcf9f2';
      ctx.fill();
      ctx.beginPath();
      ctx.arc(bodyLength/4 + 1, -bodyHeight/5 - 1, bodyLength/16, 0, 2 * Math.PI);
      ctx.fillStyle = '#0f1f2b';
      ctx.fill();
      ctx.beginPath();
      ctx.arc(bodyLength/4 + 2, -bodyHeight/5 - 2, bodyLength/28, 0, 2 * Math.PI);
      ctx.fillStyle = 'white';
      ctx.fill();

      ctx.restore();
    }

    function drawFood() {
      for (let i = 0; i < foodPellets.length; i++) {
        const f = foodPellets[i];
        ctx.beginPath();
        ctx.arc(f.x, f.y, f.size * 0.5, 0, 2 * Math.PI);
        ctx.fillStyle = '#f5b16b';
        ctx.shadowColor = '#e0853a';
        ctx.shadowBlur = 18;
        ctx.fill();
        // inner shine
        ctx.shadowBlur = 8;
        ctx.beginPath();
        ctx.arc(f.x-1, f.y-1, f.size * 0.2, 0, 2 * Math.PI);
        ctx.fillStyle = '#fcdba0';
        ctx.fill();
      }
      ctx.shadowBlur = 0;
    }

    // ----------  animation loop ----------
    function animate() {
      // update fish AI
      for (let i = 0; i < fishes.length; i++) {
        updateFish(fishes[i], i);
      }

      // draw everything
      drawBackground();

      // draw food first (behind fish)
      drawFood();

      // draw all fish
      for (let f of fishes) {
        drawFish(f);
      }

      // extra bubble details
      ctx.fillStyle = 'rgba(200, 240, 255, 0.08)';
      for (let i=0; i<8; i++) {
        ctx.beginPath();
        ctx.arc(120 + i*100, 80 + i*30, 5 + i*2, 0, 2*Math.PI);
        ctx.fill();
      }

      requestAnimationFrame(animate);
    }

    animate();

    // ----------  reset / extra  ----------
    // right click context menu prevention
    canvas.addEventListener('contextmenu', (e) => e.preventDefault());

    // optionally add food with right click (just for testing) – but we keep left click only
    // double click to scatter food? not needed – but fine

    // if food list gets too large (just in case)
    setInterval(() => {
      if (foodPellets.length > 80) {
        foodPellets.splice(0, foodPellets.length - 60);
        updateFoodCounter();
      }
    }, 4000);

    // update counter after load
    updateFoodCounter();
  })();
</script>
</body>
</html>
```
### Aquarium Mechanics & Interaction
Here's how the virtual aquarium works and how you can play with it.
*   **Feeding the Fish:** Simply left-click anywhere inside the aquarium to drop a piece of food. A counter at the bottom tracks the number of food pieces present.
*   **Realistic Fish Behavior:** Each fish has a unique color, size, and swimming speed. When food is present, each fish will dynamically calculate which piece is closest and swim directly toward it to eat.
*   **Visual & Physical Feedback:** Fish have animated tails and fins. They will also gently bounce off the aquarium walls, and their swimming speed increases slightly when chasing food.

Here's a single-file HTML clock application with a minimalist wall clock design, featuring smooth second-hand movement and China Standard Time display.
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no">
  <title>Minimalist Wall Clock · Beijing Time</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      background: linear-gradient(145deg, #d4d9e2 0%, #b8bfcc 100%);
      min-height: 100vh;
      display: flex;
      justify-content: center;
      align-items: center;
      font-family: 'Segoe UI', 'Roboto', system-ui, -apple-system, sans-serif;
      padding: 16px;
    }

    /* CLOCK DIAL — high-end shadow, white background, rounded border */
    .clock-dial {
      position: relative;
      width: min(85vw, 480px);
      height: min(85vw, 480px);
      background: #fcfcfc;
      border-radius: 50%;
      box-shadow: 
        0 20px 35px rgba(0, 0, 0, 0.25),
        0 6px 12px rgba(0, 0, 0, 0.15),
        inset 0 -4px 8px rgba(0, 0, 0, 0.05),
        inset 0 4px 8px rgba(255, 255, 255, 0.7);
      border: 2px solid rgba(30, 30, 40, 0.5);
      transition: box-shadow 0.1s ease;
    }

    /* scale container: full-size, pins rotation center */
    .scale-container {
      position: absolute;
      width: 100%;
      height: 100%;
      top: 0;
      left: 0;
      border-radius: 50%;
    }

    /* each scale tick — dynamic rotation */
    .scale-tick {
      position: absolute;
      bottom: 50%;          /* start from center, go upward */
      left: 50%;
      transform-origin: 50% 100%;  /* rotate from bottom (center) */
      width: 2px;
      height: 50%;          /* half of dial → radius */
      pointer-events: none;
    }

    /* the line element inside tick */
    .scale-tick-line {
      display: block;
      width: 100%;
      height: 12%;          /* relative to tick height (50% of dial) */
      background: #a0a8b6;
      border-radius: 2px;
      position: absolute;
      top: 0;
      left: 0;
    }

    /* thicker & darker for exact hour (every 5 ticks) */
    .scale-tick.exact .scale-tick-line {
      background: #3a3f4a;
      width: 3px;
      height: 18%;          /* longer / thicker */
      box-shadow: 0 0 6px rgba(0,0,0,0.1);
    }

    /* ——— NUMBERS (1–12) ——— */
    .number-container {
      position: absolute;
      width: 100%;
      height: 100%;
      top: 0;
      left: 0;
      border-radius: 50%;
      pointer-events: none;
    }

    .clock-number {
      position: absolute;
      width: 32px;
      height: 32px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: clamp(1.2rem, 4vw, 1.8rem);
      font-weight: 400;
      color: #2d313a;
      transform: translate(-50%, -50%);
      text-shadow: 0 1px 2px rgba(255,255,255,0.6);
      letter-spacing: 0.5px;
    }

    /* ——— HANDS ——— */
    .hand {
      position: absolute;
      bottom: 50%;
      left: 50%;
      transform-origin: 50% 100%;
      border-radius: 8px;
      pointer-events: none;
      transition: none; /* controlled by JS */
    }

    .hour-hand {
      width: 6px;
      height: 30%;
      margin-left: -3px;
      background: #1e2229;
      box-shadow: 0 4px 10px rgba(0,0,0,0.2);
      border-radius: 6px;
      z-index: 10;
    }

    .minute-hand {
      width: 4px;
      height: 40%;
      margin-left: -2px;
      background: #1e2229;
      box-shadow: 0 4px 8px rgba(0,0,0,0.15);
      border-radius: 4px;
      z-index: 15;
    }

    .second-hand {
      width: 2.5px;
      height: 43%;
      margin-left: -1.25px;
      background: #c73a3a;
      box-shadow: 0 2px 12px rgba(199, 58, 58, 0.4);
      border-radius: 3px;
      z-index: 20;
      transition: none; 
    }

    /* center cap (styling) */
    .center-cap {
      position: absolute;
      width: 14px;
      height: 14px;
      background: #2d313a;
      border-radius: 50%;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      z-index: 25;
      box-shadow: 0 0 8px rgba(0,0,0,0.2);
      border: 2px solid #f5f5f7;
    }

    /* ——— TEXT INFO: upper (time) & lower (date/week) ——— */
    .info-text {
      position: absolute;
      left: 50%;
      transform: translateX(-50%);
      text-align: center;
      width: 80%;
      font-weight: 450;
      letter-spacing: 0.8px;
      color: #1e2229;
      text-shadow: 0 1px 4px rgba(255,255,255,0.5);
      pointer-events: none;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }

    .time-display {
      top: 20%;
      font-size: clamp(1.6rem, 6vw, 2.8rem);
      font-weight: 500;
      letter-spacing: 2px;
      color: #1f232b;
    }

    .date-display {
      bottom: 22%;
      font-size: clamp(0.9rem, 3vw, 1.4rem);
      font-weight: 400;
      color: #3b414d;
      background: rgba(245, 245, 247, 0.3);
      padding: 0.2rem 1rem;
      border-radius: 40px;
      backdrop-filter: blur(1px);
      width: auto;
      max-width: 90%;
      box-shadow: inset 0 0 0 1px rgba(255,255,255,0.5);
    }

    /* responsiveness */
    @media (max-width: 480px) {
      .clock-dial {
        width: 88vw;
        height: 88vw;
      }
      .time-display {
        top: 16%;
      }
      .date-display {
        bottom: 18%;
      }
    }

    /* subtle transition for hands when not rotating (smooth) */
    .hand-smooth {
      transition: transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
    }
  </style>
</head>
<body>
  <div class="clock-dial" id="clockDial">
    <!-- scales generated via JS (60 ticks) -->
    <div class="scale-container" id="scaleContainer"></div>

    <!-- numbers 1-12 -->
    <div class="number-container" id="numberContainer"></div>

    <!-- hands -->
    <div class="hand hour-hand" id="hourHand"></div>
    <div class="hand minute-hand" id="minuteHand"></div>
    <div class="hand second-hand" id="secondHand"></div>

    <!-- center decorative cap -->
    <div class="center-cap"></div>

    <!-- text upper: time (24h) -->
    <div class="info-text time-display" id="timeDisplay">00:00:00</div>
    <!-- text lower: date + week -->
    <div class="info-text date-display" id="dateDisplay">--, ---</div>
  </div>

  <script>
    (function() {
      // ----- build scales (60 ticks) -----
      const scaleContainer = document.getElementById('scaleContainer');
      for (let i = 0; i < 60; i++) {
        const tick = document.createElement('div');
        tick.className = 'scale-tick';
        if (i % 5 === 0) tick.classList.add('exact');
        // rotation: each tick = 6°
        const rotation = i * 6;
        tick.style.transform = `rotate(${rotation}deg)`;
        const line = document.createElement('span');
        line.className = 'scale-tick-line';
        tick.appendChild(line);
        scaleContainer.appendChild(tick);
      }

      // ----- build numbers (1-12) -----
      const numberContainer = document.getElementById('numberContainer');
      const radiusFactor = 0.78; // relative to half size
      for (let i = 1; i <= 12; i++) {
        const angle = (i * 30) * Math.PI / 180; // 30° each hour
        // clock numbers: 12 at top (270° in standard math, but we adjust)
        // we want 12 at -90° (top), 3 at 0°, etc.
        // offset by -90° (PI/2)
        const x = 0.5 + radiusFactor * 0.5 * Math.sin(angle);
        const y = 0.5 - radiusFactor * 0.5 * Math.cos(angle);
        const numDiv = document.createElement('div');
        numDiv.className = 'clock-number';
        numDiv.style.left = `${x * 100}%`;
        numDiv.style.top = `${y * 100}%`;
        numDiv.textContent = i;
        numberContainer.appendChild(numDiv);
      }

      // ----- DOM refs -----
      const hourHand = document.getElementById('hourHand');
      const minuteHand = document.getElementById('minuteHand');
      const secondHand = document.getElementById('secondHand');
      const timeDisplay = document.getElementById('timeDisplay');
      const dateDisplay = document.getElementById('dateDisplay');

      // ----- smooth second hand: use requestAnimationFrame loop -----
      let smoothAngleSecond = 0;
      let lastTimestamp = 0;
      let animationId = null;

      // ----- update clock (time, angles, text) -----
      function updateClock() {
        // get Beijing time (UTC+8) using toLocaleString then parse
        const beijingTimeStr = new Date().toLocaleString('en-US', { timeZone: 'Asia/Shanghai' });
        // example: "4/17/2025, 14:35:22" (M/d/yyyy, HH:mm:ss)
        const parsed = new Date(beijingTimeStr);
        // fallback: if parsing fails (very rare) use local time with offset
        let now;
        if (!isNaN(parsed.getTime())) {
          now = parsed;
        } else {
          // robust fallback: offset manually
          const local = new Date();
          const utc = local.getTime() + local.getTimezoneOffset() * 60000;
          now = new Date(utc + 8 * 3600000);
        }

        const hours = now.getHours();
        const minutes = now.getMinutes();
        const seconds = now.getSeconds();
        const milliseconds = now.getMilliseconds();

        // ----- compute angles (smooth second) -----
        // hour: 30° per hour + 0.5° per minute + 0.5/60 per second (≈ smooth)
        const hourAngle = (hours % 12) * 30 + minutes * 0.5 + seconds * (0.5 / 60) + milliseconds * (0.5 / 60000);
        // minute: 6° per minute + 0.1° per second (smooth)
        const minuteAngle = minutes * 6 + seconds * 0.1 + milliseconds * 0.0001;
        // second: smooth (6° per second, continuous)
        const secondAngle = seconds * 6 + milliseconds * 0.006;

        // apply rotations
        hourHand.style.transform = `rotate(${hourAngle}deg)`;
        minuteHand.style.transform = `rotate(${minuteAngle}deg)`;
        secondHand.style.transform = `rotate(${secondAngle}deg)`;

        // ----- update text: time (24h) -----
        const hh = String(hours).padStart(2, '0');
        const mm = String(minutes).padStart(2, '0');
        const ss = String(seconds).padStart(2, '0');
        timeDisplay.textContent = `${hh}:${mm}:${ss}`;

        // ----- date and day of week (Beijing) -----
        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        const dayOfWeek = dayNames[now.getDay()];
        const year = now.getFullYear();
        const month = String(now.getMonth() + 1).padStart(2, '0');
        const day = String(now.getDate()).padStart(2, '0');
        dateDisplay.textContent = `${year}.${month}.${day} · ${dayOfWeek}`;
      }

      // ----- animation loop with requestAnimationFrame for smooth second hand -----
      function tickClock(timestamp) {
        updateClock();
        animationId = requestAnimationFrame(tickClock);
      }

      // start the loop
      animationId = requestAnimationFrame(tickClock);

      // optional: cleanup if needed (not crucial for single page)
      window.addEventListener('beforeunload', function() {
        if (animationId) cancelAnimationFrame(animationId);
      });

      // Edge / older browser compatibility: setInterval fallback? but rAF works on Edge
      // also run immediate to avoid initial flash
      updateClock();
    })();
  </script>
</body>
</html>
```
### Design & Functionality
This clock combines a realistic dial with dynamic timekeeping. Here's how it works:
- **Visual Design**: The clock face uses a clean white background, a dark rounded border, and a subtle 3D shadow for a premium, minimalist look. The hour and minute hands are slender and black, while the second hand is a highlighted red for easy distinction.
- **Time Display**: The upper text area shows the current time in a 24-hour format (large font). The lower area displays the date and day of the week, all centered for a balanced layout.
- **Smooth Movement**: The second hand moves continuously (not in ticks) thanks to a `requestAnimationFrame` loop, creating a fluid, high-end watch feel. All hands update their angles smoothly, including the hour and minute hands which account for milliseconds.

```javascript
const http = require('http');
const fs = require('fs');
const path = require('path');

const PORT = 8080;
const HOST = '127.0.0.1';
const DATA_FILE = path.join(__dirname, 'tickets.json');

class TicketStore {
  constructor(filePath) {
    this.filePath = filePath;
    this.tickets = [];
    this.writeLock = false;
    this.pendingWrites = [];
    this.load();
  }

  load() {
    try {
      if (fs.existsSync(this.filePath)) {
        const data = fs.readFileSync(this.filePath, 'utf8');
        this.tickets = JSON.parse(data);
        this.ensureValidStructure();
      } else {
        this.tickets = [];
        this.saveSync();
      }
    } catch (err) {
      console.error('Error loading tickets:', err.message);
      this.tickets = [];
      this.saveSync();
    }
  }

  ensureValidStructure() {
    if (!Array.isArray(this.tickets)) {
      this.tickets = [];
    }
    this.tickets = this.tickets.filter(t => t && typeof t === 'object');
  }

  saveSync() {
    try {
      fs.writeFileSync(this.filePath, JSON.stringify(this.tickets, null, 2), 'utf8');
    } catch (err) {
      console.error('Error saving tickets:', err.message);
    }
  }

  async save() {
    return new Promise((resolve, reject) => {
      const doWrite = () => {
        fs.writeFile(this.filePath, JSON.stringify(this.tickets, null, 2), 'utf8', (err) => {
          this.writeLock = false;
          if (err) {
            reject(err);
            return;
          }
          resolve();
          const next = this.pendingWrites.shift();
          if (next) {
            this.writeLock = true;
            next();
          }
        });
      };

      if (this.writeLock) {
        this.pendingWrites.push(doWrite);
      } else {
        this.writeLock = true;
        doWrite();
      }
    });
  }

  getAll(status, priority) {
    let result = [...this.tickets];
    if (status) {
      result = result.filter(t => t.status === status);
    }
    if (priority) {
      result = result.filter(t => t.priority === priority);
    }
    return result;
  }

  getById(id) {
    return this.tickets.find(t => t.id === id) || null;
  }

  async create(ticketData) {
    const ticket = {
      id: this.generateId(),
      subject: ticketData.subject,
      description: ticketData.description || '',
      priority: ticketData.priority || 'medium',
      status: ticketData.status || 'open',
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    };
    this.tickets.push(ticket);
    await this.save();
    return ticket;
  }

  async update(id, updates) {
    const index = this.tickets.findIndex(t => t.id === id);
    if (index === -1) return null;

    const allowedFields = ['subject', 'description', 'priority', 'status'];
    const ticket = this.tickets[index];

    for (const field of allowedFields) {
      if (updates[field] !== undefined) {
        ticket[field] = updates[field];
      }
    }
    ticket.updated_at = new Date().toISOString();
    this.tickets[index] = ticket;
    await this.save();
    return ticket;
  }

  async delete(id) {
    const index = this.tickets.findIndex(t => t.id === id);
    if (index === -1) return false;
    this.tickets.splice(index, 1);
    await this.save();
    return true;
  }

  getMetrics() {
    const now = new Date();
    const metrics = {
      by_status: { open: 0, in_progress: 0, resolved: 0 },
      by_priority: { low: 0, medium: 0, high: 0 },
      average_open_age_seconds: 0
    };

    let openTicketsCount = 0;
    let totalAgeSeconds = 0;

    for (const ticket of this.tickets) {
      if (metrics.by_status[ticket.status] !== undefined) {
        metrics.by_status[ticket.status]++;
      }
      if (metrics.by_priority[ticket.priority] !== undefined) {
        metrics.by_priority[ticket.priority]++;
      }
      if (ticket.status === 'open') {
        openTicketsCount++;
        const created = new Date(ticket.created_at);
        totalAgeSeconds += (now - created) / 1000;
      }
    }

    metrics.average_open_age_seconds = openTicketsCount > 0 
      ? Math.round(totalAgeSeconds / openTicketsCount) 
      : 0;

    return metrics;
  }

  generateId() {
    return Date.now().toString(36) + Math.random().toString(36).substr(2, 9);
  }
}

const store = new TicketStore(DATA_FILE);

function parseBody(req) {
  return new Promise((resolve, reject) => {
    let body = '';
    req.on('data', chunk => {
      body += chunk.toString();
    });
    req.on('end', () => {
      try {
        resolve(body ? JSON.parse(body) : {});
      } catch (err) {
        reject(new Error('Invalid JSON'));
      }
    });
    req.on('error', reject);
  });
}

function sendJSON(res, statusCode, data) {
  const body = JSON.stringify(data);
  res.writeHead(statusCode, {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, POST, PATCH, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Content-Length': Buffer.byteLength(body)
  });
  res.end(body);
}

function validateTicket(ticketData, isUpdate = false) {
  const errors = [];

  if (!ticketData.subject && !isUpdate) {
    errors.push('subject is required');
  }

  if (ticketData.priority && !['low', 'medium', 'high'].includes(ticketData.priority)) {
    errors.push('priority must be low, medium, or high');
  }

  if (ticketData.status && !['open', 'in_progress', 'resolved'].includes(ticketData.status)) {
    errors.push('status must be open, in_progress, or resolved');
  }

  return errors;
}

function parseId(url) {
  const match = url.match(/^\/tickets\/([a-zA-Z0-9]+)$/);
  return match ? match[1] : null;
}

function parseURL(url) {
  const [pathname, queryString] = url.split('?');
  const params = {};
  if (queryString) {
    queryString.split('&').forEach(pair => {
      const [key, value] = pair.split('=');
      if (key) params[decodeURIComponent(key)] = decodeURIComponent(value || '');
    });
  }
  return { pathname, params };
}

const server = http.createServer(async (req, res) => {
  try {
    const { pathname, params } = parseURL(req.url);
    const method = req.method.toUpperCase();

    // CORS preflight
    if (method === 'OPTIONS') {
      res.writeHead(204, {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'GET, POST, PATCH, DELETE, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type',
        'Access-Control-Max-Age': '86400'
      });
      res.end();
      return;
    }

    // Routes
    if (pathname === '/tickets' && method === 'GET') {
      const status = params.status || null;
      const priority = params.priority || null;
      const tickets = store.getAll(status, priority);
      sendJSON(res, 200, tickets);

    } else if (pathname === '/tickets' && method === 'POST') {
      const body = await parseBody(req);
      const errors = validateTicket(body, false);
      if (errors.length > 0) {
        sendJSON(res, 400, { error: 'Validation failed', details: errors });
        return;
      }
      const ticket = await store.create(body);
      sendJSON(res, 201, ticket);

    } else if (pathname === '/metrics' && method === 'GET') {
      const metrics = store.getMetrics();
      sendJSON(res, 200, metrics);

    } else if (pathname.startsWith('/tickets/')) {
      const id = parseId(pathname);
      if (!id) {
        sendJSON(res, 400, { error: 'Invalid ticket ID format' });
        return;
      }

      if (method === 'GET') {
        const ticket = store.getById(id);
        if (!ticket) {
          sendJSON(res, 404, { error: 'Ticket not found' });
          return;
        }
        sendJSON(res, 200, ticket);

      } else if (method === 'PATCH') {
        const body = await parseBody(req);
        if (Object.keys(body).length === 0) {
          sendJSON(res, 400, { error: 'No fields to update' });
          return;
        }
        const errors = validateTicket(body, true);
        if (errors.length > 0) {
          sendJSON(res, 400, { error: 'Validation failed', details: errors });
          return;
        }
        const ticket = await store.update(id, body);
        if (!ticket) {
          sendJSON(res, 404, { error: 'Ticket not found' });
          return;
        }
        sendJSON(res, 200, ticket);

      } else if (method === 'DELETE') {
        const deleted = await store.delete(id);
        if (!deleted) {
          sendJSON(res, 404, { error: 'Ticket not found' });
          return;
        }
        sendJSON(res, 200, { message: 'Ticket deleted', id });

      } else {
        sendJSON(res, 405, { error: 'Method not allowed' });
      }

    } else {
      sendJSON(res, 404, { error: 'Route not found' });
    }

  } catch (err) {
    if (err.message === 'Invalid JSON') {
      sendJSON(res, 400, { error: 'Invalid JSON in request body' });
    } else {
      console.error('Server error:', err);
      sendJSON(res, 500, { error: 'Internal server error' });
    }
  }
});

server.listen(PORT, HOST, () => {
  console.log(`Server running at http://${HOST}:${PORT}/`);
});
