            box-shadow: 0 2px 4px rgba(59,130,246,0.2);
        }
        .btn-add:hover {
            background: #2563eb;
        }

        /* ---- 三列网格 (响应式) ---- */
        .board-columns {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 1.2rem;
            margin-top: 0.5rem;
        }

        /* 窄屏 → 纵向排列 */
        @media (max-width: 720px) {
            .board-columns {
                grid-template-columns: 1fr;
                gap: 1.5rem;
            }
        }

        .column {
            background: #eef2f5;
            border-radius: 20px;
            padding: 1rem 0.8rem 0.8rem;
            min-height: 320px;
            display: flex;
            flex-direction: column;
            transition: background 0.1s;
        }
        .column-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 0 0.3rem 0.8rem 0.3rem;
            font-weight: 600;
            color: #0f172a;
            border-bottom: 2px solid rgba(0,0,0,0.05);
        }
        .column-header h2 {
            font-size: 1.1rem;
            letter-spacing: 0.3px;
        }
        .count-badge {
            background: rgba(0,0,0,0.08);
            padding: 0.15rem 0.9rem;
            border-radius: 40px;
            font-size: 0.8rem;
            font-weight: 500;
        }

        /* ---- 卡片容器 (用于拖拽放置) ---- */
        .card-list {
            flex: 1;
            padding: 0.3rem 0;
            display: flex;
            flex-direction: column;
            gap: 0.7rem;
            min-height: 60px;
        }

        /* ---- 任务卡片 ---- */
        .task-card {
            background: white;
            border-radius: 14px;
            padding: 0.9rem 1rem 0.8rem;
            box-shadow: 0 2px 6px rgba(0,0,0,0.03);
            transition: box-shadow 0.2s, transform 0.1s;
            position: relative;
            border-left: 4px solid #e2e8f0;
            cursor: grab;
            /* 方便拖拽 */
            user-select: none;
        }
        .task-card:active {
            cursor: grabbing;
            box-shadow: 0 8px 18px rgba(0,0,0,0.08);
            transform: scale(1.01);
        }
        .task-card.dragging {
            opacity: 0.5;
            box-shadow: 0 10px 20px rgba(0,0,0,0.1);
        }
        /* 优先级左边框 */
        .task-card.priority-high {
            border-left-color: #ef4444;
        }
        .task-card.priority-medium {
            border-left-color: #f59e0b;
        }
        .task-card.priority-low {
            border-left-color: #22c55e;
        }

        .card-title {
            font-weight: 600;
            font-size: 1rem;
            margin-bottom: 0.3rem;
            word-break: break-word;
            padding-right: 10px;
        }
        .card-desc {
            font-size: 0.85rem;
            color: #475569;
            margin-bottom: 0.45rem;
            word-break: break-word;
            white-space: pre-wrap;
        }
        .card-meta {
            display: flex;
            justify-content: space-between;
            align-items: center;
            font-size: 0.7rem;
            color: #64748b;
            margin-top: 0.2rem;
            flex-wrap: wrap;
            gap: 0.2rem 0.5rem;
        }
        .card-meta .priority-tag {
            font-weight: 500;
            padding: 0.1rem 0.6rem;
            border-radius: 30px;
            background: #f1f5f9;
        }
        .card-actions {
            display: flex;
            gap: 0.6rem;
            margin-top: 0.5rem;
            flex-wrap: wrap;
        }
        .card-actions button {
            background: transparent;
            border: 1px solid #d1d5db;
            padding: 0.2rem 0.7rem;
            border-radius: 30px;
            font-size: 0.7rem;
            cursor: pointer;
            transition: 0.1s;
            color: #1e293b;
        }
        .card-actions button:hover {
            background: #f1f5f9;
            border-color: #94a3b8;
        }
        .card-actions .move-btn-group {
            display: inline-flex;
            gap: 0.2rem;
        }
        .move-btn-group button {
            padding: 0.2rem 0.5rem;
            font-size: 0.7rem;
        }
        .delete-btn {
            color: #b91c1c;
            border-color: #fca5a5;
        }
        .delete-btn:hover {
            background: #fee2e2 !important;
        }

        /* ---- 新建/编辑模态 ---- */
        .modal-overlay {
            position: fixed;
            inset: 0;
            background: rgba(0,0,0,0.3);
            backdrop-filter: blur(3px);
            display: flex;
            justify-content: center;
            align-items: center;
            z-index: 1000;
        }
        .modal {
            background: white;
            border-radius: 28px;
            padding: 2rem 1.8rem 1.8rem;
            max-width: 420px;
            width: 90%;
            box-shadow: 0 20px 60px rgba(0,0,0,0.15);
        }
        .modal h3 {
            margin-bottom: 1.2rem;
            font-weight: 600;
            color: #0f172a;
        }
        .modal label {
            font-size: 0.85rem;
            font-weight: 500;
            display: block;
            margin: 0.7rem 0 0.2rem;
            color: #334155;
        }
        .modal input, .modal textarea, .modal select {
            width: 100%;
            padding: 0.6rem 0.8rem;
            border: 1px solid #cbd5e1;
            border-radius: 14px;
            font-size: 0.9rem;
            outline: none;
            transition: 0.15s;
        }
        .modal input:focus, .modal textarea:focus, .modal select:focus {
            border-color: #3b82f6;
            box-shadow: 0 0 0 3px rgba(59,130,246,0.2);
        }
        .modal textarea {
            resize: vertical;
            min-height: 60px;
        }
        .modal-actions {
            display: flex;
            justify-content: flex-end;
            gap: 0.8rem;
            margin-top: 1.4rem;
        }
        .modal-actions button {
            padding: 0.5rem 1.5rem;
            border-radius: 40px;
            border: none;
            font-weight: 500;
            cursor: pointer;
        }
        .modal-actions .btn-cancel {
            background: #e2e8f0;
            color: #1e293b;
        }
        .modal-actions .btn-confirm {
            background: #3b82f6;
            color: white;
        }
        .hidden {
            display: none !important;
        }
    </style>
</head>
<body>
<div id="app">
    <!-- 头部 -->
    <header class="board-header">
        <h1>📋 轻量看板</h1>
        <div class="search-box">
            <input type="text" id="searchInput" placeholder="搜索任务…" aria-label="搜索关键词">
        </div>
        <select id="filterSelect" class="filter-select" aria-label="筛选优先级">
            <option value="all">所有优先级</option>
            <option value="high">高</option>
            <option value="medium">中</option>
            <option value="low">低</option>
        </select>
        <button class="btn-add" id="addTaskBtn">+ 新任务</button>
    </header>

    <!-- 三列 -->
    <div class="board-columns" id="boardColumns">
        <!-- 待办 -->
        <div class="column" data-status="todo">
            <div class="column-header"><h2>📌 待办</h2><span class="count-badge" id="todoCount">0</span></div>
            <div class="card-list" id="todoList" data-status="todo"></div>
        </div>
        <!-- 进行中 -->
        <div class="column" data-status="inprogress">
            <div class="column-header"><h2>⚡ 进行中</h2><span class="count-badge" id="inprogressCount">0</span></div>
            <div class="card-list" id="inprogressList" data-status="inprogress"></div>
        </div>
        <!-- 已完成 -->
        <div class="column" data-status="done">
            <div class="column-header"><h2>✅ 已完成</h2><span class="count-badge" id="doneCount">0</span></div>
            <div class="card-list" id="doneList" data-status="done"></div>
        </div>
    </div>
</div>

<!-- 模态框（新建/编辑共用） -->
<div id="modalOverlay" class="modal-overlay hidden">
    <div class="modal">
        <h3 id="modalTitle">📝 新建任务</h3>
        <label>标题 *</label>
        <input type="text" id="taskTitleInput" placeholder="任务标题" maxlength="60">
        <label>备注</label>
        <textarea id="taskDescInput" placeholder="可选备注" rows="2"></textarea>
        <label>优先级</label>
        <select id="taskPriorityInput">
            <option value="low">低</option>
            <option value="medium" selected>中</option>
            <option value="high">高</option>
        </select>
        <div class="modal-actions">
            <button class="btn-cancel" id="modalCancelBtn">取消</button>
            <button class="btn-confirm" id="modalConfirmBtn">保存</button>
        </div>
    </div>
</div>

<script>
    (function() {
        "use strict";

        // ----- 状态管理 -----
        let tasks = [];               // 所有任务 { id, title, desc, priority, status, createdAt }
        let editingId = null;        // 正在编辑的任务id，null表示新建
        let searchKeyword = '';
        let filterPriority = 'all';

        // DOM 引用
        const todoList = document.getElementById('todoList');
        const inprogressList = document.getElementById('inprogressList');
        const doneList = document.getElementById('doneList');
        const todoCount = document.getElementById('todoCount');
        const inprogressCount = document.getElementById('inprogressCount');
        const doneCount = document.getElementById('doneCount');
        const searchInput = document.getElementById('searchInput');
        const filterSelect = document.getElementById('filterSelect');
        const addBtn = document.getElementById('addTaskBtn');
        const modalOverlay = document.getElementById('modalOverlay');
        const modalTitle = document.getElementById('modalTitle');
        const taskTitleInput = document.getElementById('taskTitleInput');
        const taskDescInput = document.getElementById('taskDescInput');
        const taskPriorityInput = document.getElementById('taskPriorityInput');
        const modalCancelBtn = document.getElementById('modalCancelBtn');
        const modalConfirmBtn = document.getElementById('modalConfirmBtn');

        // 获取卡片容器映射
        const containerMap = {
            'todo': todoList,
            'inprogress': inprogressList,
            'done': doneList
        };

        // 计数器更新
        function updateCounts() {
            const filtered = getFilteredTasks();
            const todo = filtered.filter(t => t.status === 'todo').length;
            const ip = filtered.filter(t => t.status === 'inprogress').length;
            const done = filtered.filter(t => t.status === 'done').length;
            todoCount.textContent = todo;
            inprogressCount.textContent = ip;
            doneCount.textContent = done;
        }

        // 返回当前过滤后的任务
        function getFilteredTasks() {
            let list = tasks;
            if (searchKeyword.trim()) {
                const kw = searchKeyword.trim().toLowerCase();
                list = list.filter(t => t.title.toLowerCase().includes(kw) || (t.desc && t.desc.toLowerCase().includes(kw)));
            }
            if (filterPriority !== 'all') {
                list = list.filter(t => t.priority === filterPriority);
            }
            return list;
        }

        // 渲染所有卡片 (根据过滤)
        function renderAll() {
            // 先清空
            todoList.innerHTML = '';
            inprogressList.innerHTML = '';
            doneList.innerHTML = '';

            const filtered = getFilteredTasks();
            filtered.forEach(task => {
                const card = createCardElement(task);
                const container = containerMap[task.status];
                if (container) container.appendChild(card);
            });

            updateCounts();
            // 重新挂载拖拽事件 (放在卡片创建之后)
            attachDragEvents();
        }

        // ----- 创建卡片 DOM -----
        function createCardElement(task) {
            const priorityLabel = { low: '低', medium: '中', high: '高' };
            const card = document.createElement('div');
            card.className = `task-card priority-${task.priority}`;
            card.setAttribute('draggable', 'true');
            card.dataset.taskId = task.id;
            card.dataset.status = task.status;

            // 标题
            const titleDiv = document.createElement('div');
            titleDiv.className = 'card-title';
            titleDiv.textContent = task.title;

            // 描述
            const descDiv = document.createElement('div');
            descDiv.className = 'card-desc';
            descDiv.textContent = task.desc || '';

            // 元数据：时间 + 优先级标签
            const metaDiv = document.createElement('div');
            metaDiv.className = 'card-meta';
            const timeSpan = document.createElement('span');
            const date = new Date(task.createdAt);
            const timeStr = `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')} ${String(date.getHours()).padStart(2,'0')}:${String(date.getMinutes()).padStart(2,'0')}`;
            timeSpan.textContent = `🕒 ${timeStr}`;
            const prioritySpan = document.createElement('span');
            prioritySpan.className = 'priority-tag';
            prioritySpan.textContent = priorityLabel[task.priority] || '中';
            metaDiv.appendChild(timeSpan);
            metaDiv.appendChild(prioritySpan);

            // 操作按钮组
            const actionsDiv = document.createElement('div');
            actionsDiv.className = 'card-actions';

            // 移动按钮组 (左移 / 右移)
            const moveGroup = document.createElement('span');
            moveGroup.className = 'move-btn-group';
            const statusOrder = ['todo', 'inprogress', 'done'];
            const currentIdx = statusOrder.indexOf(task.status);
            // 左移
            if (currentIdx > 0) {
                const leftBtn = document.createElement('button');
                leftBtn.textContent = '◀ 左移';
                leftBtn.setAttribute('aria-label', '向左移动');
                leftBtn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    moveTaskTo(task.id, statusOrder[currentIdx - 1]);
                });
                moveGroup.appendChild(leftBtn);
            }
            // 右移
            if (currentIdx < statusOrder.length - 1) {
                const rightBtn = document.createElement('button');
                rightBtn.textContent = '右移 ▶';
                rightBtn.setAttribute('aria-label', '向右移动');
                rightBtn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    moveTaskTo(task.id, statusOrder[currentIdx + 1]);
                });
                moveGroup.appendChild(rightBtn);
            }
            if (moveGroup.children.length > 0) actionsDiv.appendChild(moveGroup);

            // 编辑按钮
            const editBtn = document.createElement('button');
            editBtn.textContent = '✎ 编辑';
            editBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                openEditModal(task.id);
            });
            actionsDiv.appendChild(editBtn);

            // 删除按钮
            const deleteBtn = document.createElement('button');
            deleteBtn.className = 'delete-btn';
            deleteBtn.textContent = '🗑 删除';
            deleteBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                if (confirm(`删除任务「${task.title}」?`)) {
                    deleteTask(task.id);
                }
            });
            actionsDiv.appendChild(deleteBtn);

            card.appendChild(titleDiv);
            card.appendChild(descDiv);
            card.appendChild(metaDiv);
            card.appendChild(actionsDiv);

            // 拖拽事件 (原生)
            card.addEventListener('dragstart', (e) => {
                e.dataTransfer.setData('text/plain', task.id);
                card.classList.add('dragging');
            });
            card.addEventListener('dragend', () => {
                card.classList.remove('dragging');
            });

            return card;
        }

        // ----- 移动任务 (提供给按钮与拖拽) -----
        function moveTaskTo(taskId, newStatus) {
            const task = tasks.find(t => t.id === taskId);
            if (!task || task.status === newStatus) return;
            task.status = newStatus;
            saveToLocal();
            renderAll();
        }

        // ----- 删除任务 -----
        function deleteTask(taskId) {
            tasks = tasks.filter(t => t.id !== taskId);
            saveToLocal();
            renderAll();
        }

        // ----- 打开新建模态 -----
        function openNewModal() {
            editingId = null;
            modalTitle.textContent = '📝 新建任务';
            taskTitleInput.value = '';
            taskDescInput.value = '';
            taskPriorityInput.value = 'medium';
            modalOverlay.classList.remove('hidden');
            taskTitleInput.focus();
        }

        // ----- 打开编辑模态 -----
        function openEditModal(taskId) {
            const task = tasks.find(t => t.id === taskId);
            if (!task) return;
            editingId = taskId;
            modalTitle.textContent = '✏️ 编辑任务';
            taskTitleInput.value = task.title;
            taskDescInput.value = task.desc || '';
            taskPriorityInput.value = task.priority;
            modalOverlay.classList.remove('hidden');
            taskTitleInput.focus();
        }

        // ----- 关闭模态 -----
        function closeModal() {
            modalOverlay.classList.add('hidden');
            editingId = null;
        }

        // ----- 保存 (新建/编辑) -----
        function saveTaskFromModal() {
            const title = taskTitleInput.value.trim();
            if (!title) {
                alert('标题不能为空');
                return;
            }
            const desc = taskDescInput.value.trim();
            const priority = taskPriorityInput.value;

            if (editingId) {
                // 编辑模式
                const task = tasks.find(t => t.id === editingId);
                if (task) {
                    task.title = title;
                    task.desc = desc;
                    task.priority = priority;
                }
            } else {
                // 新建模式，默认放到待办
                const newTask = {
                    id: Date.now() + '_' + Math.random().toString(36).slice(2, 6),
                    title: title,
                    desc: desc,
                    priority: priority,
                    status: 'todo',
                    createdAt: Date.now()
                };
                tasks.push(newTask);
            }
            saveToLocal();
            renderAll();
            closeModal();
        }

        // ----- localStorage 操作 -----
        function saveToLocal() {
            localStorage.setItem('kanban_tasks', JSON.stringify(tasks));
        }

        function loadFromLocal() {
            const stored = localStorage.getItem('kanban_tasks');
            if (stored) {
                try {
                    tasks = JSON.parse(stored);
                    // 兼容旧数据: 确保每个任务有 createdAt
                    tasks = tasks.map(t => ({ ...t, createdAt: t.createdAt || Date.now() }));
                } catch (e) {
                    tasks = [];
                }
            } else {
                // 一些初始示例
                tasks = [
                    { id: '1', title: '设计原型', desc: '完成主页低保真', priority: 'high', status: 'todo', createdAt: Date.now() - 3600000 },
                    { id: '2', title: '开发看板', desc: '实现拖拽功能', priority: 'medium', status: 'inprogress', createdAt: Date.now() - 7200000 },
                    { id: '3', title: '写周报', desc: '汇总本周进展', priority: 'low', status: 'done', createdAt: Date.now() - 86400000 }
                ];
                saveToLocal();
            }
        }

        // ----- 拖拽放置 (列容器监听) -----
        function attachDragEvents() {
            const containers = [todoList, inprogressList, doneList];
            containers.forEach(container => {
                // 移除旧监听器 (避免重复绑定，简单重新绑定)
                // 但为了简单，使用新监听 (其实每次render重新绑定)
                // 这里利用事件委托: 在父级 boardColumns 上监听
            });
            // 我们使用全局监听，避免重复注册
        }

        // 全局拖拽放置处理 (在boardColumns上监听)
        function setupDragAndDrop() {
            const board = document.getElementById('boardColumns');
            board.addEventListener('dragover', (e) => {
                e.preventDefault(); // 必须
                const targetList = e.target.closest('.card-list');
                if (targetList) {
                    e.dataTransfer.dropEffect = 'move';
                }
            });

            board.addEventListener('drop', (e) => {
                e.preventDefault();
                const targetList = e.target.closest('.card-list');
                if (!targetList) return;
                const newStatus = targetList.dataset.status;
                const taskId = e.dataTransfer.getData('text/plain');
                if (taskId && newStatus) {
                    moveTaskTo(taskId, newStatus);
                }
            });
        }

        // ----- 搜索与筛选事件 -----
        function setupFilters() {
            searchInput.addEventListener('input', () => {
                searchKeyword = searchInput.value;
                renderAll();
            });
            filterSelect.addEventListener('change', () => {
                filterPriority = filterSelect.value;
                renderAll();
            });
        }

        // ----- 初始化 -----
        function init() {
            loadFromLocal();
            renderAll();
            setupDragAndDrop();
            setupFilters();

            // 新建按钮
            addBtn.addEventListener('click', openNewModal);

            // 模态按钮
            modalCancelBtn.addEventListener('click', closeModal);
            modalConfirmBtn.addEventListener('click', saveTaskFromModal);
            // 点击遮罩关闭
            modalOverlay.addEventListener('click', (e) => {
                if (e.target === modalOverlay) closeModal();
            });
            // 回车保存
            taskTitleInput.addEventListener('keydown', (e) => {
                if (e.key === 'Enter') { e.preventDefault(); saveTaskFromModal(); }
            });
        }

        init();
    })();
</script>
</body>
</html>
