<body>
<div class="clock-wrapper">
    <div class="clock-face" id="clockFace">
        <!-- canvas 绘制刻度 -->
        <canvas class="tick-canvas" id="tickCanvas" width="760" height="760"></canvas>

        <!-- 数字 (通过JS放置) -->
