    <div class="text-info date-text" id="dateText">Loading...</div>
</div>

<script>
    (function() {
        "use strict";

        // ----- build scales (60 marks) -----
        const scaleLayer = document.getElementById('scaleLayer');
        for (let i = 0; i < 60; i++) {
            const angle = i * 6;   // 6° per mark
            const mark = document.createElement('div');
            mark.className = 'scale-mark';
            if (i % 5 === 0) {
                mark.classList.add('hour-mark');
            }
            mark.style.transform = `rotate(${angle}deg)`;
            scaleLayer.appendChild(mark);
        }

        // ----- build numbers (1–12) -----
        const numberLayer = document.getElementById('numberLayer');
        const radius = 155; // relative to center (based on 380px dial)
        const centerX = 190, centerY = 190; // half of 380

        for (let i = 1; i <= 12; i++) {
            // angle for numbers: 12 at top (-90°), then clockwise
            const angleDeg = (i * 30) - 90;   // 12h = 0° => -90° in standard math
            const rad = (angleDeg * Math.PI) / 180;
            const x = centerX + radius * Math.cos(rad);
            const y = centerY + radius * Math.sin(rad);

            const numEl = document.createElement('div');
            numEl.className = 'num';
            numEl.textContent = i === 0 ? '12' : i; // i from 1..12
            numEl.style.left = x + 'px';
            numEl.style.top = y + 'px';
            numberLayer.appendChild(numEl);
        }

        // ----- DOM references for hands & text -----
        const hourHand = document.getElementById('hourHand');
        const minuteHand = document.getElementById('minuteHand');
        const secondHand = document.getElementById('secondHand');
        const timeText = document.getElementById('timeText');
        const dateText = document.getElementById('dateText');

        // ----- helper: get Beijing time (UTC+8) via toLocaleString (Edge friendly) -----
        function getBeijingDateTime() {
            // Use 'en-US' to get reliable parsing; timeZone: asia/shanghai
            const dateStr = new Date().toLocaleString('en-US', { timeZone: 'Asia/Shanghai' });
            // format: "M/D/YYYY, H:MM:SS AM/PM"  or  "M/D/YYYY, H:MM:SS" (24h? depends)
            // to be robust, we parse via Date constructor after replacing locale string
            // But safer: use Intl.DateTimeFormat with explicit values.
            // We'll use a more direct method: get UTC time and add 8 hours.
            const now = new Date();
            const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
            const beijingTime = new Date(utc + (8 * 3600000));
            return beijingTime;
        }

        // ----- update clock (angles, text) with smooth second hand -----
        function updateClock() {
            const beijing = getBeijingDateTime();

            const hours = beijing.getHours();
            const minutes = beijing.getMinutes();
            const seconds = beijing.getSeconds();
            const milliseconds = beijing.getMilliseconds();

            // smooth second movement: include milliseconds as fraction
            const secondsFraction = seconds + (milliseconds / 1000);
            // second hand: 360° / 60 = 6° per second
            const secondAngle = secondsFraction * 6;  

            // minute hand: 360° / 60 = 6° per minute, plus fine from seconds
            const minuteAngle = (minutes + secondsFraction / 60) * 6;

            // hour hand: 360° / 12 = 30° per hour, plus fine from minutes
            const hourAngle = ((hours % 12) + minutes / 60 + secondsFraction / 3600) * 30;

            // apply rotation (transform-origin already bottom center)
            hourHand.style.transform = `rotate(${hourAngle}deg)`;
            minuteHand.style.transform = `rotate(${minuteAngle}deg)`;
            secondHand.style.transform = `rotate(${secondAngle}deg)`;

            // ----- upper text: 24h format HH:MM:SS (leading zeros) -----
            const hh = String(hours).padStart(2, '0');
            const mm = String(minutes).padStart(2, '0');
            const ss = String(seconds).padStart(2, '0');
            timeText.textContent = `${hh}:${mm}:${ss}`;

            // ----- lower text: date + day of week (Beijing) -----
            // Use toLocaleDateString for Chinese/English weekdays; use 'en-US' for consistent Western names
            const dateOptions = { 
                timeZone: 'Asia/Shanghai', 
                year: 'numeric', 
                month: '2-digit', 
                day: '2-digit',
                weekday: 'long' 
            };
            // Edge supports 'long' weekday
            const formatter = new Intl.DateTimeFormat('en-US', dateOptions);
            const formatted = formatter.format(beijing);
            // formatted example: "04/12/2025, Saturday" or "04/12/2025, Saturday" – but we want nice layout
            // Parse: we can reorder. Let's extract parts using toLocaleDateString 
            // A simpler approach: build manually.
            const year = beijing.getFullYear();
            const month = String(beijing.getMonth() + 1).padStart(2, '0');
            const day = String(beijing.getDate()).padStart(2, '0');
            const weekdays = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
            const weekday = weekdays[beijing.getDay()];
            dateText.textContent = `${year}.${month}.${day} · ${weekday}`;
        }

        // initial call
        updateClock();

        // use requestAnimationFrame for silky smooth second hand (better than setInterval)
        let rafId = null;
        function tick() {
            updateClock();
            rafId = requestAnimationFrame(tick);
        }

        // start animation loop
        rafId = requestAnimationFrame(tick);

        // optional cleanup (if needed)
        window.addEventListener('beforeunload', function() {
            if (rafId) cancelAnimationFrame(rafId);
        });

        // fallback: Edge legacy? requestAnimationFrame is supported. 
        // But extra setInterval as safety (not needed, but keeps compatibility if raf pauses)
        // However we use raf, which is smooth and compatible.
        // Also update each second to avoid drift.
        // for extra precision, also update via setInterval every 1s? But raf already does.
        // We'll just keep raf.
    })();
</script>
</body>
</html>
```
### Clock Interface and Functionality
The page simulates a physical wall clock with smooth, accurate timekeeping. Here's how it works:
*   **Visual Design:** The clock features a clean, white dial with a 3D shadow effect. The hour and minute hands are slender and dark, while the second hand is a smooth-moving red line for easy distinction.
*   **Time Display:** The upper half of the clock face shows the current time in a large, 24-hour digital format (HH:MM:SS). The lower half displays the current date and day of the week.
*   **Core Mechanism:** The `updateClock()` function calculates the precise rotation angles for each hand based on the current Beijing Time (UTC+8). It uses `requestAnimationFrame` for a silky-smooth movement of the second hand.

