<div class="clock-dial" id="clockDial">
    <!-- scales (generated via JS) -->
    <div class="scales" id="scalesContainer"></div>
    <!-- numbers -->
    <div class="clock-numbers" id="numbersContainer"></div>
    <!-- hands -->
