          { id: '3', title: '测试登录功能', note: '', priority: 'low', status: 'done', createdAt: Date.now() - 60000*60 },
        ];
      }
      // 确保每个任务都有status字段（向后兼容）
      tasks = tasks.map(t => ({ ...t, status: t.status || 'todo' }));
    }

