    function getNextStatus(currentStatus) {
      const map = { 'todo': 'inprogress', 'inprogress': 'done', 'done': 'todo' };
      return map[currentStatus] || 'todo';
    }

    // ---------- 渲染层 ----------
    const todoList = document.getElementById('todoList');
